project/contracts/interfaces/ICryptoPunk.content:
// SPDX-License-Identifier: MIT
pragma solidity 0.8.34;

/// @title  ICryptoPunksMarket
///
/// @notice Minimal surface of the original CryptoPunksMarket contract used by
///         vaults, auctions, and bid books in this repo.
interface ICryptoPunksMarket {
    /// @notice Active sell offer tuple from the original CryptoPunksMarket.
    struct Offer {
        bool isForSale;
        uint256 punkIndex;
        address seller;
        uint256 minValue;
        address onlySellTo;
    }

    // ─────────────────────────────────── Sales ──────────────────────────────────

    /// @notice Returns sale details for a Punk.
    function punksOfferedForSale(uint256 punkIndex)
        external
        view
        returns (
            bool isForSale,
            uint256 punkIndex_,
            address seller,
            uint256 minValue,
            address onlySellTo
        );

    /// @notice Returns the owner of a Punk.
    function punkIndexToAddress(uint256 punkIndex) external view returns (address);

    /// @notice Offers a Punk for public sale.
    function offerPunkForSale(uint256 punkIndex, uint256 minSalePriceInWei) external;

    /// @notice Offers a Punk for sale to one address.
    function offerPunkForSaleToAddress(
        uint256 punkIndex,
        uint256 minSalePriceInWei,
        address toAddress
    ) external;

    /// @notice Removes a Punk sale offer.
    function punkNoLongerForSale(uint256 punkIndex) external;

    /// @notice Buys a Punk that is offered for sale.
    function buyPunk(uint256 punkIndex) external payable;

    /// @notice Transfers a Punk to another address.
    function transferPunk(address to, uint256 punkIndex) external;

    // ─────────────────────────────────── Bids ───────────────────────────────────

    /// @notice Places a bid on a Punk. The market locks `msg.value` and
    ///         refunds any previously outbid bidder via `pendingWithdrawals`.
    function enterBidForPunk(uint256 punkIndex) external payable;

    /// @notice Withdraws the caller's standing bid on a Punk, returning the
    ///         locked ETH to the caller.
    function withdrawBidForPunk(uint256 punkIndex) external;

    /// @notice Accepts the standing bid for a Punk at >= minPrice.
    function acceptBidForPunk(uint256 punkIndex, uint256 minPrice) external;

    // ───────────────────────────────── Proceeds ─────────────────────────────────

    /// @notice Withdraws pending ETH from the Punk market.
    function withdraw() external;

    /// @notice ETH owed to `claimant` and awaiting withdrawal.
    function pendingWithdrawals(address claimant) external view returns (uint256);
}

project/contracts/interfaces/IPunksVault.content:
// SPDX-License-Identifier: MIT
pragma solidity 0.8.34;

/// @title  IPunksVault
/// @notice External surface of `PunksVault` — a deterministic, user-owned
///         smart account for CryptoPunks custody. Holds punks across any
///         CryptoPunks-compatible market at a single address per user.
///         Protocols integrate by being approved as operators; the owner
///         uses `execute` for everything else.
/// @author 1001
interface IPunksVault {
    struct Call {
        address target;
        uint256 value;
        bytes data;
    }

    error NotOwner();
    error NotAuthorized();
    error NotFactory();
    error AlreadyInitialized();
    error ExecutionFailed(bytes returnData);
    error ZeroAddress();
    error BrokenPunksV1MarketUnsupported();

    /// @dev Deliberately not named `ApprovalForAll`: this vault's operator
    ///      role is strictly stronger than ERC-721's (it also conveys ETH
    ///      spend authority via `buyPunk` / `enterBidForPunk`). A distinct
    ///      event name + selector prevents wallets and indexers from
    ///      auto-classifying it under the ERC-721 trust model.
    event OperatorSet(address indexed operator, bool approved);

    /// @dev Indexes the vault as a smart account.
    event Executed(address indexed target, uint256 value, bytes data);

    // ─────────────────────────── Identity ─────────────────────────────────

    /// @notice The permanent owner of this vault. Bound for life during
    ///         factory initialization.
    function owner() external view returns (address);

    /// @notice The factory that deployed every clone. The only address
    ///         allowed to call `factoryInitialize`.
    function FACTORY() external view returns (address);

    // ───────────────────────── Operator role ──────────────────────────────

    /// @notice Approves `operator` as a full-trust agent for this vault.
    ///         Operators may move any punk this vault holds on any market
    ///         (transfer to any recipient, list at any price including zero,
    ///         accept any standing bid) AND spend the vault's ETH balance
    ///         via `buyPunk` / `enterBidForPunk` up to `address(this).balance`.
    ///         There is no narrower per-punk delegation: the owner is the
    ///         only path for one-off custody moves, via `execute` or by
    ///         calling the delegated surface directly.
    /// @dev    Deliberately not named `setApprovalForAll`: this role is
    ///         strictly stronger than the ERC-721 setter of the same name,
    ///         and the distinct selector keeps wallets / integrators from
    ///         under-pricing the authority through ERC-721 heuristics.
    function setOperator(address operator, bool approved) external;

    function isOperator(address operator) external view returns (bool);

    // ──────────────── Punk market — delegated surface ─────────────────────
    //
    // Owner-or-operator gated.

    /// @notice Clean replacement for `offerPunkForSaleToAddress(.., 0, x)`:
    ///         moves a punk out of the vault without polluting the canonical
    ///         market with a zero-priced listing.
    function transferPunk(address market, uint256 punkIndex, address to) external;

    function offerPunkForSale(
        address market,
        uint256 punkIndex,
        uint256 minSalePriceWei
    ) external;

    /// @notice Lists for sale only to `toAddress`. Used by auction houses
    ///         to set up real-priced PunkBought round-trips at settlement.
    function offerPunkForSaleToAddress(
        address market,
        uint256 punkIndex,
        uint256 minSalePriceWei,
        address toAddress
    ) external;

    function punkNoLongerForSale(address market, uint256 punkIndex) external;

    /// @notice Accepts the standing bid at >= minPrice. Proceeds land in
    ///         the market's `pendingWithdrawals[vault]` — call
    ///         `withdrawFromMarket` to move them into the vault's balance.
    function acceptBidForPunk(
        address market,
        uint256 punkIndex,
        uint256 minPrice
    ) external;

    // ──────────────── Punk market — spending surface ──────────────────────
    //
    // Owner-or-operator gated. `payable` so callers may top up the vault
    // inline; `value` is what the market sees and may exceed `msg.value`
    // by drawing on existing balance. Surplus `msg.value` beyond `value`
    // stays in the vault.

    /// @notice Buys the Punk at `(market, punkIndex)`, forwarding `value`
    ///         wei to the market. Funded from any combination of the
    ///         attached `msg.value` and the vault's existing balance.
    /// @dev Owner or operator.
    function buyPunk(address market, uint256 punkIndex, uint256 value)
        external payable;

    /// @notice Places a bid on `(market, punkIndex)`, locking `value` wei
    ///         in the market. Funded as in `buyPunk`. The market refunds
    ///         any previously outbid bidder via its own `pendingWithdrawals`.
    /// @dev Owner or operator.
    function enterBidForPunk(address market, uint256 punkIndex, uint256 value)
        external payable;

    /// @notice Withdraws the vault's standing bid on `(market, punkIndex)`,
    ///         returning the locked ETH to the vault's balance.
    /// @dev Owner or operator.
    function withdrawBidForPunk(address market, uint256 punkIndex) external;

    // ─────────────────────────── Stash ────────────────────────────────────

    /// @notice The canonical Yuga Labs StashFactory on Ethereum mainnet,
    ///         used by `stash` to resolve the EOA owner's Stash address.
    function STASH_FACTORY() external view returns (address);

    /// @notice The canonical CryptoPunksMarket V2 contract on Ethereum
    ///         mainnet, used by `stash` because Stash only supports
    ///         canonical V2 Punks.
    function CRYPTOPUNKS() external view returns (address);

    /// @notice The bugged CryptoPunks V1 market on Ethereum mainnet.
    /// @dev    Direct sales through this market misattribute sale proceeds,
    ///         so vault sale listings and buys reject this address.
    function CRYPTOPUNKS_V1() external view returns (address);

    /// @notice Forwards a Punk to the EOA owner's canonical Stash on Yuga
    ///         Labs' StashFactory, deploying the Stash on first use. The
    ///         Stash is owned by the EOA (not the vault), so listings,
    ///         bids, and withdrawals from the Stash proceed through normal
    ///         EOA tooling rather than this vault.
    function stash(uint256 punkIndex) external;

    // ─────────────────────────── Proceeds ─────────────────────────────────

    /// @notice Pulls this vault's `pendingWithdrawals` on `market` into
    ///         the vault's ETH balance.
    /// @dev Owner or operator. Operators already have unbounded ETH-spend
    ///      authority via `buyPunk` / `enterBidForPunk`, so gating proceeds
    ///      collection separately would be security theater — the trust
    ///      assumption is unchanged.
    function withdrawFromMarket(address market) external;

    /// @notice Pulls this vault's `pendingWithdrawals` on `market` and
    ///         forwards the withdrawn ETH to `recipient`.
    /// @dev Owner or operator. Only the ETH received from this withdraw
    ///      call is forwarded; any pre-existing vault balance remains in
    ///      the vault.
    function withdrawFromMarketTo(address market, address recipient) external;

    // ──────────────── Owner-only generic execution ────────────────────────

    /// @notice Calls `target` with `value` ETH and `data`. The path for
    ///         everything the explicit punks surface doesn't cover: ERC20
    ///         claims, ENS subdomain management, ERC721 / ERC1155 sweeps,
    ///         sending ETH to the owner's wallet, future protocols.
    /// @dev    Uses CALL, never DELEGATECALL — vault state cannot be
    ///         hijacked by a misbehaving target. Revert data bubbles via
    ///         `ExecutionFailed`.
    function execute(address target, uint256 value, bytes calldata data)
        external payable returns (bytes memory);

    /// @notice Atomic batched `execute`. All-or-nothing.
    function executeBatch(Call[] calldata calls)
        external payable returns (bytes[] memory);

    // ──────────────── Factory-only setup paths ────────────────────────────

    /// @notice Sets the vault owner and pre-approves `operators` at deploy
    ///         time. Callable exactly once, only by `FACTORY`.
    function factoryInitialize(address owner, address[] calldata operators) external;

    /// @notice Additively approves `operators` after deployment when routed
    ///         through the factory by the current vault owner.
    /// @dev    Callable only by `FACTORY`; `expectedOwner` must match the
    ///         vault's owner. Cannot revoke approvals or change ownership.
    function factoryApproveOperators(
        address expectedOwner,
        address[] calldata operators
    ) external;
}

project/contracts/interfaces/IStashFacto.content:
// SPDX-License-Identifier: MIT
pragma solidity 0.8.34;

/// @notice Minimal slice of Yuga Labs' StashFactory used by `PunksVault.stash`
///         to look up and (if needed) deploy the EOA owner's canonical Stash.
interface IStashFactory {
    /// @notice CREATE2-derived address of the Stash for `owner`. Returns the
    ///         deterministic address whether or not the Stash has been
    ///         deployed yet.
    function stashAddressFor(address owner) external view returns (address);

    /// @notice Permissionlessly deploys the Stash for `owner` if it has not
    ///         been deployed yet. Returns the Stash address either way.
    function deployStash(address owner) external returns (address);
}

project/contracts/PunksVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity 0.8.34;

import {ERC1271} from "solady/src/accounts/ERC1271.sol";
import {Receiver} from "solady/src/accounts/Receiver.sol";

import "./interfaces/IPunksVault.sol";
import "./interfaces/ICryptoPunksMarket.sol";
import "./interfaces/IStashFactory.sol";

/// @title  PunksVault
/// @notice Deterministic, user-owned smart account for CryptoPunks custody.
///
///         Protocols integrate as approved operators on the vault, so they can
///         manage canonical punks with the same flexibility as wrapped assets
///         while ensuring sales clear through the original CryptoPunksMarket.
///
///         The owner uses `execute` and `isValidSignature` for everything else.
/// @author 1001
contract PunksVault is IPunksVault, Receiver, ERC1271 {
    /// @inheritdoc IPunksVault
    address public immutable FACTORY;

    /// @inheritdoc IPunksVault
    address public constant CRYPTOPUNKS = 0xb47e3cd837dDF8e4c57F05d70Ab865de6e193BBB;

    /// @inheritdoc IPunksVault
    address public constant CRYPTOPUNKS_V1 = 0x6Ba6f2207e343923BA692e5Cae646Fb0F566DB8D;

    /// @inheritdoc IPunksVault
    address public constant STASH_FACTORY = 0x000000000000A6fA31F5fC51c1640aAc76866750;

    /// @inheritdoc IPunksVault
    address public owner;

    /// @dev True once `factoryInitialize` has run. Pre-set on the
    ///      implementation itself by the constructor so the template
    ///      can never be hijacked.
    bool private _initialized;

    /// @dev Tracks operators authorized to invoke owner-or-operator
    ///      gated flows.
    mapping(address operator => bool) private _operatorApproved;

    /// @notice Deploys the implementation. Clones inherit `FACTORY` via the
    ///         shared runtime bytecode and receive their owner through
    ///         `factoryInitialize`.
    /// @dev    The implementation itself is sealed against `factoryInitialize`
    ///         here so it cannot be co-opted by anyone who calls it directly.
    constructor(address factory_) {
        if (factory_ == address(0)) revert ZeroAddress();
        FACTORY = factory_;
        _initialized = true;
    }

    // ─────────────────────────────── Operator role ───────────────────────────────

    /// @inheritdoc IPunksVault
    function setOperator(address operator, bool approved) external {
        if (msg.sender != owner) revert NotOwner();
        if (operator == address(0)) revert ZeroAddress();
        if (_operatorApproved[operator] == approved) return;
        _operatorApproved[operator] = approved;
        emit OperatorSet(operator, approved);
    }

    /// @inheritdoc IPunksVault
    function isOperator(address operator) external view returns (bool) {
        return _operatorApproved[operator];
    }

    // ────────────────────── Punk market — delegated surface ──────────────────────

    /// @inheritdoc IPunksVault
    function transferPunk(address market, uint256 punkIndex, address to) external {
        if (!_isOwnerOrOperator(msg.sender)) revert NotAuthorized();
        ICryptoPunksMarket(market).transferPunk(to, punkIndex);
    }

    /// @inheritdoc IPunksVault
    function offerPunkForSale(address market, uint256 punkIndex, uint256 minSalePriceWei)
        external
    {
        if (!_isOwnerOrOperator(msg.sender)) revert NotAuthorized();
        _requireNoBrokenV1SaleMarket(market);
        ICryptoPunksMarket(market).offerPunkForSale(punkIndex, minSalePriceWei);
    }

    /// @inheritdoc IPunksVault
    function offerPunkForSaleToAddress(
        address market,
        uint256 punkIndex,
        uint256 minSalePriceWei,
        address toAddress
    ) external {
        if (!_isOwnerOrOperator(msg.sender)) revert NotAuthorized();
        // Note we allow V1 listings here specifically. Only list to
        // trusted protocols that ensure return of sale proceeds.
        ICryptoPunksMarket(market)
            .offerPunkForSaleToAddress(punkIndex, minSalePriceWei, toAddress);
    }

    /// @inheritdoc IPunksVault
    function punkNoLongerForSale(address market, uint256 punkIndex) external {
        if (!_isOwnerOrOperator(msg.sender)) revert NotAuthorized();
        ICryptoPunksMarket(market).punkNoLongerForSale(punkIndex);
    }

    /// @inheritdoc IPunksVault
    function acceptBidForPunk(address market, uint256 punkIndex, uint256 minPrice) external {
        if (!_isOwnerOrOperator(msg.sender)) revert NotAuthorized();
        ICryptoPunksMarket(market).acceptBidForPunk(punkIndex, minPrice);
    }

    // ────────────────────── Punk market — spending surface ───────────────────────

    /// @inheritdoc IPunksVault
    function buyPunk(address market, uint256 punkIndex, uint256 value)
        external
        payable
    {
        if (!_isOwnerOrOperator(msg.sender)) revert NotAuthorized();
        _requireNoBrokenV1SaleMarket(market);
        ICryptoPunksMarket(market).buyPunk{value: value}(punkIndex);
    }

    /// @inheritdoc IPunksVault
    function enterBidForPunk(address market, uint256 punkIndex, uint256 value)
        external
        payable
    {
        if (!_isOwnerOrOperator(msg.sender)) revert NotAuthorized();
        ICryptoPunksMarket(market).enterBidForPunk{value: value}(punkIndex);
    }

    /// @inheritdoc IPunksVault
    function withdrawBidForPunk(address market, uint256 punkIndex) external {
        if (!_isOwnerOrOperator(msg.sender)) revert NotAuthorized();
        ICryptoPunksMarket(market).withdrawBidForPunk(punkIndex);
    }

    // ───────────────────────────────── Proceeds ──────────────────────────────────

    /// @inheritdoc IPunksVault
    function withdrawFromMarket(address market) external {
        if (!_isOwnerOrOperator(msg.sender)) revert NotAuthorized();
        ICryptoPunksMarket(market).withdraw();
    }

    /// @inheritdoc IPunksVault
    function withdrawFromMarketTo(address market, address recipient) external {
        if (!_isOwnerOrOperator(msg.sender)) revert NotAuthorized();
        if (recipient == address(0)) revert ZeroAddress();
        uint256 pending = ICryptoPunksMarket(market).pendingWithdrawals(address(this));
        uint256 balanceBefore = address(this).balance;
        ICryptoPunksMarket(market).withdraw();
        uint256 withdrawn = address(this).balance - balanceBefore;
        // Cap at pre-call pending so any other ETH that lands here mid-call isn't forwarded.
        if (withdrawn > pending) withdrawn = pending;
        if (withdrawn != 0) {
            (bool ok, bytes memory ret) = recipient.call{value: withdrawn}("");
            if (!ok) revert ExecutionFailed(ret);
        }
    }

    // ─────────────────────────────────── Stash ───────────────────────────────────

    /// @inheritdoc IPunksVault
    /// @dev    The Stash CREATE2 derivation is owner-keyed, so the vault
    ///         and its EOA owner resolve to different Stashes — sending
    ///         to `stashAddressFor(owner)` lands the Punk in the EOA's
    ///         existing Stash (or a freshly deployed one).
    function stash(uint256 punkIndex) external {
        if (!_isOwnerOrOperator(msg.sender)) revert NotAuthorized();
        address eoaOwner = owner;
        address stashAddr = IStashFactory(STASH_FACTORY).stashAddressFor(eoaOwner);
        if (stashAddr.code.length == 0) {
            IStashFactory(STASH_FACTORY).deployStash(eoaOwner);
        }
        ICryptoPunksMarket(CRYPTOPUNKS).transferPunk(stashAddr, punkIndex);
    }

    // ─────────────────────── Owner-only generic execution ────────────────────────

    /// @inheritdoc IPunksVault
    function execute(address target, uint256 value, bytes calldata data)
        external
        payable
        returns (bytes memory)
    {
        if (msg.sender != owner) revert NotOwner();
        (bool ok, bytes memory ret) = target.call{value: value}(data);
        if (!ok) revert ExecutionFailed(ret);
        emit Executed(target, value, data);
        return ret;
    }

    /// @inheritdoc IPunksVault
    function executeBatch(Call[] calldata calls)
        external
        payable
        returns (bytes[] memory results)
    {
        if (msg.sender != owner) revert NotOwner();
        uint256 len = calls.length;
        results = new bytes[](len);
        for (uint256 i; i < len;) {
            Call calldata c = calls[i];
            (bool ok, bytes memory ret) = c.target.call{value: c.value}(c.data);
            if (!ok) revert ExecutionFailed(ret);
            results[i] = ret;
            emit Executed(c.target, c.value, c.data);
            unchecked { ++i; }
        }
    }

    // ───────────────────────── Factory-only setup paths ─────────────────────────

    /// @inheritdoc IPunksVault
    function factoryInitialize(address owner_, address[] calldata operators) external {
        if (msg.sender != FACTORY) revert NotFactory();
        if (_initialized) revert AlreadyInitialized();
        if (owner_ == address(0)) revert ZeroAddress();
        owner = owner_;
        _initialized = true;
        _setOperators(operators);
    }

    /// @inheritdoc IPunksVault
    function factoryApproveOperators(
        address expectedOwner,
        address[] calldata operators
    ) external {
        if (msg.sender != FACTORY) revert NotFactory();
        if (owner != expectedOwner) revert NotOwner();
        _setOperators(operators);
    }

    // ───────────────────────────────── Internals ─────────────────────────────────

    function _setOperators(address[] calldata operators) private {
        uint256 len = operators.length;
        for (uint256 i; i < len;) {
            address op = operators[i];
            if (op == address(0)) revert ZeroAddress();
            if (!_operatorApproved[op]) {
                _operatorApproved[op] = true;
                emit OperatorSet(op, true);
            }
            unchecked { ++i; }
        }
    }

    /// @dev The vault's single auth tier: owner or any operator. Used for
    ///      every non-owner-only path; gates both the delegated market
    ///      surface and the ETH-spending surface.
    function _isOwnerOrOperator(address caller) private view returns (bool) {
        return caller == owner || _operatorApproved[caller];
    }

    function _requireNoBrokenV1SaleMarket(address market) private pure {
        if (market == CRYPTOPUNKS_V1) revert BrokenPunksV1MarketUnsupported();
    }

    function _domainNameAndVersion()
        internal
        pure
        override
        returns (string memory name, string memory version)
    {
        name = "PunksVault";
        version = "1";
    }

    function _erc1271Signer() internal view override returns (address) {
        return owner;
    }
}
